    private static final String CLASSE_COMPTEUR_1_OU_0_5 = "Classe compteur != 1 ou 0.5 ";
    public static final String RED_CPT_CL_1 = "RED_CPT_CL1";
    public static final String RED_CPT_CL_05 = "RED_CPT_CL05";
    public static final String MORE_THAN_ONE_VALID_PRICE_IN_THE_TABLE = "More than one valid price in the table";
    private static final String ENT_CPT_MONO = "ENT_CPT_MONO";
    private static final String LOC_CPT_MONO = "LOC_CPT_MONO";
    private static final String ENT_CPT_TI = "ENT_CPT_TI";
    private static final String LOC_CPT_TI = "LOC_CPT_TI";
    private static final String ENT_CPT_TRI_SUP = "ENT_CPT_TRI_SUP";
    private static final String LOC_CPT_TRI_SUP = "LOC_CPT_TRI_SUP";
    private static final String ENT_CPT_TRI_INF = "ENT_CPT_TRI_INF";
    private static final String LOC_CPT_TRI_INF = "LOC_CPT_TRI_INF";
    private static final String G030_000 = "030/000";
    private static final String SUBSCRIPTION_ERROR_MESSAGE = "Subscription error";
    private static final String DON_T_CALL_THIS_SCRIPT_OUT_OF_RATING_JOB = "don't call this script out of rating job";
    private static final String PDS_ERROR_MESSAGE = "PDS Error id_pds :";
    private static final String SERVICE_INSTANCES_ERROR_MESSAGE = "ServiceInstances[] ERROR id_pds :";
    private static final String SERVICE_INSTANCE_ERROR_MESSAGE = "ServiceInstances ERROR id_pds :";
    private static final String OFFER_ERROR_MESSAGE = "Offer ERROR id_pds :";
    private static final String ACCESS_ERROR_MESSAGE = "Access error id_pds :";
    private String CPT_BT_QUERY;
    private String CPT_HTA_QUERY;
    private String OFFER;
    private String PROD;
    private BigDecimal unitPriceWithoutTax;
    private BigDecimal qantity;
    private List<Map<String, Object>> pdsTable;
    private String accessUserId;
    CustomTableService customTableService = getServiceInterface(CustomTableService.class.getSimpleName());


    @Override
    public void execute(RatingContext ratingContext) {
        initializeContext();
        WalletOperation walletOperation = findWalletOperation(ratingContext);
        Subscription subscription = findSubscription(walletOperation);
        ServiceInstance chargeCode = walletOperation.getChargeInstance().getServiceInstance();
        applyAccordingToSubscription(subscription, chargeCode);
        calculateRating(ratingContext, walletOperation);
    }

    private void initializeContext() {
        accessUserId = "";
        qantity = BigDecimal.valueOf(1);
        CPT_BT_QUERY = " id in( select id from ct_grille_tarifaire where CURRENT_DATE BETWEEN date_debut_validite AND date_fin_validite and code in('price_one','price_two'))\n";
        CPT_HTA_QUERY = "id in (select id\n" +
                "             from ct_grille_tarifaire\n" +
                "             where CURRENT_DATE BETWEEN date_debut_validite AND date_fin_validite\n" +
                "             and code = 'RED_CPT_CL1')\n";
    }

    private void applyAccordingToSubscription(Subscription subscription, ServiceInstance prod) {
        findAccesPoint(subscription);
        findOffer(subscription);
        findProduct(subscription, prod);
        findPds();
        Map<String, Object> pds = pdsTable.get(0);
        String cf_nature = String.valueOf(subscription.getCfValue(CF_NATURE));
        validateNature(cf_nature);
        if (Objects.equals(cf_nature, BT)) {
            applyRulesForBT(pds);
        }
        if (Objects.equals(cf_nature, HTA)) {
            applyRulesForHTA(pds);
        }
    }


    private void calculateRating(RatingContext ratingContext, WalletOperation walletOperation) {
        ratingContext.calculate(walletOperation, ratingContext.reCalculate(unitPriceWithoutTax,walletOperation), qantity, OperationTypeEnum.DEBIT, OFFER, PROD);
    }

    private void applyRulesForBT(Map<String, Object> pds) {
        Object transformateur_intensite = pds.get(TRANSFORMATEUR_INTENSITE);
        Object nb_fils = pds.get(NB_FILS);
        List<String> prices = updateQueryBT(pds, nb_fils, transformateur_intensite);
        unitPriceWithoutTax = getPrice(prices, BT);
    }

    private void applyRulesForHTA(Map<String, Object> pds) {
        Object classe_compteur = pds.get(CLASSE_COMPTEUR);
        if (classe_compteur == null || (((Number) classe_compteur).doubleValue() != 0.5 && ((Number) classe_compteur).doubleValue() != 1.0)) {
            throwNoClasseCompteurError();
        }
        if (((Number) classe_compteur).doubleValue() == 0.5) {
            unitPriceWithoutTax = getPrice(List.of(RED_CPT_CL_05), HTA);
        }
        if (((Number) classe_compteur).doubleValue() == 1.0) {
            unitPriceWithoutTax = getPrice(List.of(RED_CPT_CL_1), HTA);
        }
    }

    private List<String> updateQueryBT(Map<String, Object> pds, Object nb_fils, Object transformateur_intensite) {
        if (nb_fils == null || ((Number) nb_fils).intValue() != 4 && ((Number) nb_fils).intValue() != 2) {
            throwNoPriceForFilsError();
        }
        if (transformateur_intensite != null && ((Boolean) transformateur_intensite)) {
            replacePricesInQueryBT(ENT_CPT_TI, LOC_CPT_TI);
            return List.of(ENT_CPT_TI, LOC_CPT_TI);
        } else if (phsage((Number) nb_fils).equals(MONOPHASE)) {
            replacePricesInQueryBT(ENT_CPT_MONO, LOC_CPT_MONO);
            return List.of(ENT_CPT_MONO, LOC_CPT_MONO);
        } else if (phsage((Number) nb_fils).equals(TRIPHASE)) {
            String gamme = pds.get(GAMME) == null || pds.get(GAMME).equals("") ? "0" : String.valueOf(pds.get(GAMME));
            if (isSuppGamme(gamme)) {
                replacePricesInQueryBT(ENT_CPT_TRI_SUP, LOC_CPT_TRI_SUP);
                return List.of(ENT_CPT_TRI_SUP, LOC_CPT_TRI_SUP);
            } else {
                replacePricesInQueryBT(ENT_CPT_TRI_INF, LOC_CPT_TRI_INF);
                return List.of(ENT_CPT_TRI_INF, LOC_CPT_TRI_INF);
            }
        }
        throw new BusinessApiException("error in update query or rerun prices Codes id_pds : " + accessUserId);
    }

    private void replacePricesInQueryBT(String priceENT, String priceLOC) {
        CPT_BT_QUERY = CPT_BT_QUERY.replace(PRICE_ONE, priceENT).replace(PRICE_TWO, priceLOC);
    }

    private boolean isSuppGamme(String gamme) {
        return gamme.compareTo(G030_000) >= 1;
    }

    private String phsage(Number nbFils) {
        return nbFils.intValue() == 2 ? MONOPHASE : TRIPHASE;
    }

    public BigDecimal getPrice(List<String> pricesCode, String cfNature) {
        if (HTA.equals(cfNature) && RED_CPT_CL_05.equals(pricesCode.get(0)))
            CPT_HTA_QUERY = CPT_HTA_QUERY.replace(RED_CPT_CL_1, RED_CPT_CL_05);
        return BT.equals(cfNature) ? getPriceBT(pricesCode) : getPriceHTA();
    }

    private BigDecimal getPriceHTA() {
        List<Map<String, Object>> list = getDataFromCT(CT_GRILLE_TARIFAIRE, Map.of(SQL, CPT_HTA_QUERY));
        if (list == null || list.isEmpty())
            throwEmptyCTGrilleTarifaireError();
        if (list.size() > 1)
            throwMoreThanOneValidPriceFoundError();
        return (BigDecimal) list.get(0).get(VALEUR);
    }

    public BigDecimal getPriceBT(List<String> pricesCode) {
        List<Map<String, Object>> list = getDataFromCT(CT_GRILLE_TARIFAIRE, Map.of(SQL, CPT_BT_QUERY));
        if (list == null || list.isEmpty())
            throwEmptyCTGrilleTarifaireError();
        if (list.size() != 2 || !verifyPrices(pricesCode, list))
            throwPriceNotFoundError();
        return calculateTotalPrice(list);
    }

    private BigDecimal calculateTotalPrice(List<Map<String, Object>> priceList) {
        return priceList.stream()
                .map(priceMap -> (BigDecimal) priceMap.get(VALEUR))
                .reduce(BigDecimal::add)
                .orElse(BigDecimal.ZERO);
    }

    private boolean verifyPrices(List<String> pricesCode, List<Map<String, Object>> list) {
        return pricesCode.stream()
                .allMatch(code -> list.stream()
                        .map(priceMap -> (String) priceMap.get(CODE))
                        .filter(Objects::nonNull)
                        .anyMatch(code::equals));
    }

    private void validateNature(String cfNature) {
        if (cfNature == null || !Objects.equals(cfNature, HTA) && !Objects.equals(cfNature, BT)) {
            throwCfNatureError();
        }
    }

    public List<Map<String, Object>> getDataFromCT(String tableName, Map<String, Object> filters) {
        try {
            return customTableService.list(tableName, new PaginationConfiguration(filters));
        } catch (Exception e) {
            logError(e);
            return Collections.emptyList();
        }
    }

    private WalletOperation findWalletOperation(RatingContext ratingContext) {
        WalletOperation walletOperation = ratingContext.getWalletOperation();
        if (walletOperation == null) {
            throwOutOfRatingJobError();
        }
        return walletOperation;
    }

    private Subscription findSubscription(WalletOperation walletOperation) {
        Subscription subscription = walletOperation.getSubscription();
        Objects.requireNonNull(subscription, SUBSCRIPTION_ERROR_MESSAGE);
        return subscription;
    }

    private void findPds() {
        pdsTable = getDataFromCT(CT_PDS, Map.of(ID_PDS, accessUserId, STATUT_PDS, ACTIF));
        if (pdsTable == null || pdsTable.size() != 1)
            throwPdsError();
    }

    private void findAccesPoint(Subscription subscription) {
        if (subscription.getAccessPoints() == null || subscription.getAccessPoints().isEmpty() || subscription.getAccessPoints().get(0) == null)
            throwAccessError();
        accessUserId = subscription.getAccessPoints().get(0).getAccessUserId();
    }

    private void findProduct(Subscription subscription, ServiceInstance prod) {
        List<ServiceInstance> serviceInstances = subscription.getServiceInstances();
        if (serviceInstances == null || serviceInstances.isEmpty())
            throwServiceInstancesError();
        Optional<ServiceInstance> serviceInstance = serviceInstances.stream()
                .filter(s -> Objects.equals(s.getCode(), prod.getCode()))
                .findFirst();
        if (serviceInstance.isPresent()) {
            PROD = serviceInstance.get().getCode();
        } else {
            throwServiceInstanceError();
        }
    }

    private void findOffer(Subscription subscription) {
        OfferTemplate offer = subscription.getOffer();
        if (offer == null || offer.getCode() == null)
            throwOfferError();
        OFFER = offer.getCode();
    }

    private void throwOutOfRatingJobError() {
        throw new BusinessApiException(DON_T_CALL_THIS_SCRIPT_OUT_OF_RATING_JOB);
    }

    private void throwCfNatureError() {
        throw new BusinessApiException(CF_NATURE_ERROR_ID_PDS + accessUserId);
    }

    private void throwPdsError() {
        throw new BusinessApiException(PDS_ERROR_MESSAGE + accessUserId);
    }

    private void throwServiceInstancesError() {
        throw new BusinessApiException(SERVICE_INSTANCES_ERROR_MESSAGE + accessUserId);
    }

    private void throwServiceInstanceError() {
        throw new BusinessApiException(SERVICE_INSTANCE_ERROR_MESSAGE + accessUserId);
    }

    private void throwOfferError() {
        throw new BusinessApiException(OFFER_ERROR_MESSAGE + accessUserId);
    }

    private void throwAccessError() {
        throw new BusinessApiException(ACCESS_ERROR_MESSAGE + accessUserId);
    }

    private void throwEmptyCTGrilleTarifaireError() {
        throw new BusinessApiException(CT_GRILLE_TARIFAIRE_IS_EMPTY_ACCESS_USER_ID + accessUserId);
    }

    private void throwPriceNotFoundError() {
        throw new BusinessApiException(ONE_OF_THIS_PRICES_DOES_NOT_EXIST);
    }

    private void throwMoreThanOneValidPriceFoundError() {
        throw new BusinessApiException(MORE_THAN_ONE_VALID_PRICE_IN_THE_TABLE);
    }

    private void throwNoPriceForFilsError() {
        throw new BusinessApiException(PAS_DE_PRIX_QUI_CORRESPOND_AU_NOMBRE_DE_FILS_ID_PDS + accessUserId);
    }

    private void throwNoClasseCompteurError() {
        throw new BusinessApiException(CLASSE_COMPTEUR_1_OU_0_5 + accessUserId);

    }

    private void logError(Exception e) {
        log.error(GET_DATA_FROM_CT_ERROR, e);
    }

}","type":"JAVA"}

{"script":"package eec.epi.scripts.valo;

import eec.epi.scripts.RatingScript;
import org.meveo.admin.util.pagination.PaginationConfiguration;
import org.meveo.api.exception.BusinessApiException;
import org.meveo.model.billing.*;
import org.meveo.model.catalog.OfferTemplate;
import org.meveo.model.rating.EDR;
import org.meveo.service.custom.CustomTableService;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.*;
import java.util.stream.Collectors;

public class RRValoTCPF extends RatingScript {

    protected static final String CH_RR_BVE_TAXECOM_PF = "CH_RR_BVE_TAXECOM_PF";
    protected static final String PX_PRIMEFIXE_BT = "PX_PRIMEFIXE_BT";
    protected static final String PX_PRIMEFIXE_HTA = "PX_PRIMEFIXE_HTA";
    protected static final String TAX_COM = "TAX_COM";
    protected static final String CF_CODE_EXPLOITATION = "cf_code_exploitation";
    public static final String CF_PUISSANCE_SOUSCRITE = "cf_puissance_souscrite";
    protected static final String TAUX = "taux";
    protected static final String CF_NATURE = "cf_nature";
    protected static final String HTA = "HTA";
    protected static final String BT = "BT";

    protected String CPT_QUERY;
    protected BigDecimal taux;
    protected BigDecimal pricePF;
    protected String subscriptionCode;
    protected Object cf_code_exploitation;


    @Override
    public void execute(RatingContext ratingContext) {
        List<Map<String, Object>> list = initializeContext(ratingContext);
        WalletOperation walletOperation = ratingContext.getWalletOperation(ratingContext);
        Subscription subscription = ratingContext.getSubscription(walletOperation);
        subscriptionCode = subscription.getCode();
        ChargeInstance chargeInstance = ratingContext.getChargeInstance(walletOperation,CH_RR_BVE_TAXECOM_PF);
        ServiceInstance productCode = chargeInstance.getServiceInstance();
        ratingContext.applyAccordingToSubscription(subscription, productCode, subscriptionCode,ratingContext);
        cf_code_exploitation = subscription.getCfValue(CF_CODE_EXPLOITATION);
        ratingContext.setPuissanceSouscrite(subscription);
        if (Objects.equals(ratingContext.getCf_nature(), BT)) {
            applyRulesForBT(ratingContext, list, cf_code_exploitation);
        }
        if (Objects.equals(ratingContext.getCf_nature(), HTA)) {
            applyRulesForHTA(ratingContext, list, cf_code_exploitation);
        }
        ratingContext.calculateTAXCOM(walletOperation, taux, ratingContext.reCalculate(pricePF,walletOperation).multiply(ratingContext.getCf_puissance_souscrite()), OperationTypeEnum.DEBIT, ratingContext.getOFFER(), ratingContext.getPROD());
    }

    private void applyRulesForHTA(RatingContext ratingContext, List<Map<String, Object>> list, Object cf_code_exploitation) {
        taux = ratingContext.getValueFromList(TAX_COM, ratingContext.getOFFER(), HTA, cf_code_exploitation, list,subscriptionCode).divide(new BigDecimal(100), RoundingMode.UNNECESSARY);
        pricePF = ratingContext.getValueFromList(PX_PRIMEFIXE_HTA, ratingContext.getOFFER(), HTA, cf_code_exploitation, list,subscriptionCode);
        pricePF = pricePF.divide(new BigDecimal(12),0, RoundingMode.HALF_UP);
    }
    private void applyRulesForBT(RatingContext ratingContext, List<Map<String, Object>> list, Object cf_code_exploitation) {
        taux = ratingContext.getValueFromList(TAX_COM, ratingContext.getOFFER(), BT, cf_code_exploitation, list,subscriptionCode).divide(new BigDecimal(100), RoundingMode.UNNECESSARY);
        pricePF = ratingContext.getValueFromList(PX_PRIMEFIXE_BT, ratingContext.getOFFER(), BT, cf_code_exploitation, list,subscriptionCode);
        pricePF = pricePF.divide(new BigDecimal(12),0, RoundingMode.HALF_UP);
    }

    private List<Map<String, Object>> initializeContext(RatingContext ratingContext) {
        subscriptionCode = "";
        taux =BigDecimal.ZERO;
        pricePF = BigDecimal.ZERO;
        cf_code_exploitation=null;
        CPT_QUERY = " id in ( select id\n" +
                "             from ct_grille_tarifaire\n" +
                "             where CURRENT_DATE BETWEEN date_debut_validite AND date_fin_validite )\n";
        return ratingContext.getValues(CPT_QUERY,subscriptionCode);
    }
}","type":"JAVA"}

{"script":"package eec.epi.scripts.releves;


import com.fasterxml.jackson.databind.ObjectMapper;
import eec.epi.scripts.JobScript;
import eec.epi.scripts.ResultIntegration;
import eec.epi.scripts.pds.structure.enums.StatusPds;
import eec.epi.scripts.releves.structure.DonneesMesure;
import eec.epi.scripts.releves.structure.Releve;
import eec.epi.scripts.releves.structure.enums.Status;
import org.meveo.admin.exception.BusinessException;
import org.meveo.model.billing.Subscription;
import org.meveo.model.crm.Customer;
import org.meveo.model.mediation.Access;
import org.meveo.service.crm.impl.CustomerService;
import org.meveo.service.custom.CustomTableService;
import org.meveo.service.medina.impl.AccessService;


import java.text.ParseException;
import java.text.SimpleDateFormat;
import java.util.*;


import static java.util.Objects.isNull;


/**
 * This class handles the integration of releves data from "ct_releves_temp" to "ct_releves".
 *
 * @author Ahmed BAHRI ahmed.bahri@iliadeconsulting.com
 */
public class RelevesIntegration extends JobScript {
    // Constants for custom table and field names
    protected static final String CT_RELEVES_TEMP = "ct_releves_temp";
    protected static final String CT_RELEVES = "ct_releves";
    protected static final String STATUT = "statut";
    protected static final String ID = "id";
    protected static final String DATE_LAST_UPDATE = "date_last_update";
    protected static final String DATE_TRAITEMENT = "date_traitement";
    protected static final String CODE_ERREUR = "code_erreur";
    protected static final String MESSAGE_ERREUR = "message_erreur";
    protected static final String CONTENU = "contenu";
    protected static final String ID_RELEVE = "id_releve";
    protected static final String NUM_COMPTEUR = "num_compteur";
    protected static final String DATE_RELEVE = "date_releve";
    protected static final String NATURE_RELEVE = "nature_releve";
    protected static final String ORIGINE = "origine";
    protected static final String ID_PDS = "id_pds";
    protected static final String CODE_RELEVE = "code_releve";
    protected static final String CODE_OBSERVATION = "code_observation";
    protected static final String CODE_RFE = "code_rfe";
    protected static final String LOT = "lot";
    protected static final String TOURNEE = "tournee";
    protected static final String EXPLOITATION = "exploitation";
    protected static final String NATURE_MESURE = "nature_mesure";
    protected static final String MESURE = "mesure";
    protected static final String UNITE = "unite";
    protected static final String STATUT_RELEVE = "statut_releve";
    protected static final String POSTE_HOROSAISONNIER = "poste_horosaisonnier";
    protected static final String SQL_RELEVE = "id in(select id from ct_releves where statut_releve in ('VALIDE','CALCULE'))";
    public static final String SQL = "SQL";
    protected List<Map<String, Object>> relevesTemp;
    protected List<Map<String, Object>> releves;
    protected List<Map<String, Object>> pdsList;
    protected ReleveValidator validator;
    protected List<Access> accessList;
    protected String customerName;
    protected SimpleDateFormat sdf;
    CustomTableService customTableService = getServiceInterface(CustomTableService.class);
    AccessService accessService = getServiceInterface(AccessService.class);
    CustomerService customerService = getServiceInterface(CustomerService.class);

    @Override
    public void execute(JobContext jobContext) {
        sdf = new SimpleDateFormat("yyyy-MM-dd");
        customerName = null;
        accessList = accessService.list();
        pdsList = getFromCT("ct_pds", prepareFilter("statut_pds", StatusPds.ACTIF.getValue()));
        validator = new ReleveValidator();
        relevesTemp = getFromCT(CT_RELEVES_TEMP, prepareFilter(STATUT, Status.A_TRAITER.getValue()));
        if (relevesTemp == null || relevesTemp.isEmpty()) {
            jobContext.reportKO("Aucune ligne a traiter dans la table " + CT_RELEVES_TEMP);
            return;
        }
        if (pdsList == null || pdsList.isEmpty()) {
            jobContext.reportKO("Aucune pds actif dans la table ct_pds");
            return;
        }
        releves = getFromCT(CT_RELEVES, prepareFilter(SQL,SQL_RELEVE));
        if (releves == null) releves = new ArrayList<>();
        traiterEntry(jobContext, relevesTemp);
    }

    /**
     * Prepares a filter map using the provided key-value pairs.
     *
     * @param keyValue Key-value pairs for the filter.
     * @return A map containing the prepared filter.
     */
    public Map<String, Object> prepareFilter(String... keyValue) {
        return Map.of(keyValue[0], keyValue[1]);
    }

    private void traiterEntry(JobContext jobContext, List<Map<String, Object>> releveList) {
        try {
            for (Map<String, Object> entry : releveList) {
                Object id = entry.get(ID);
                Releve releve = getReleveInfo((String) entry.get(CONTENU));
                if (releve == null) {
                    jobContext.reportKO("CONTENU : Parse json fail, ID Releve dans la table ct_releves_temp : " + id);
                    return;
                }
                ResultIntegration result = verfiyReleveBeforeIntegration(releve);
                if (!result.isResult()) {
                    makeResult(id, result, Status.FAIL);
                    String errorRecord = "";
                    if (id != null) errorRecord = "Intégration " + entry.get("id") + " ";
                    jobContext.reportKO(errorRecord + result.getError());
                    continue;
                }
                IntgrateAValidReleve(releve);
                makeResult(id, result, Status.SUCCESS);
                jobContext.reportOK("Intégration " + entry.get("id") + " succès");

            }
        } catch (Exception e) {
            throw new BusinessException("integrationReleves fail : " + e.getMessage());
        }
    }

    /**
     * Integrates a valid Releve object into the target custom table "ct_releves".
     *
     * @param releve The valid Releve object to be integrated.
     */
    private void IntgrateAValidReleve(Releve releve) {
        try {
            boolean hasCodeReleve = !isNull(releve.getCodeReleve());
            boolean hasCodeObservation = !isNull(releve.getCodeObservation());
            boolean hasCodeRfe = !isNull(releve.getCodeRfe());
            boolean hasExploitation = !isNull(releve.getExploitation());
            List<DonneesMesure> donneesMesures = releve.getDonneesMesures();
            for (DonneesMesure donneesMesure : donneesMesures) {
                Map<String, Object> releveDetail = new HashMap<>();
                releveDetail.put(ID_RELEVE, releve.getIdReleve());
                releveDetail.put(NUM_COMPTEUR, releve.getNumCompteur());
                releveDetail.put(DATE_RELEVE, validator.parseDate(releve.getDateReleve()));
                releveDetail.put(NATURE_RELEVE, releve.getNatureReleve());
                releveDetail.put(ORIGINE, releve.getOrigineReleve());
                releveDetail.put(ID_PDS, releve.getIdPds());
                if (hasCodeReleve) releveDetail.put(CODE_RELEVE, releve.getCodeReleve());
                if (hasCodeObservation) releveDetail.put(CODE_OBSERVATION, releve.getCodeObservation());
                if (hasCodeRfe) releveDetail.put(CODE_RFE, releve.getCodeRfe());
                if (!isNull(releve.getLot()))
                    releveDetail.put(LOT, releve.getLot());
                if (!isNull(releve.getTournee()))
                    releveDetail.put(TOURNEE, releve.getTournee());
                if (hasExploitation) releveDetail.put(EXPLOITATION, releve.getExploitation());
                releveDetail.put(POSTE_HOROSAISONNIER, donneesMesure.getPosteHorosaisonnier());
                releveDetail.put(NATURE_MESURE, donneesMesure.getNatureMesure());
                releveDetail.put(MESURE, donneesMesure.getMesure());
                releveDetail.put(UNITE, donneesMesure.getUnite());
                releveDetail.put(STATUT_RELEVE, releve.getNatureReleve().equals("POSE") ? Status.CALCULE.getValue() : Status.VALIDE.getValue());
                releves.add(releveDetail);
                customTableService.create(CT_RELEVES, releveDetail);
            }
        } catch (Exception e) {
            throw new BusinessException("Fail Create data in table " + CT_RELEVES + " : " + e.getMessage());
        }
    }


    /**
     * Verifies if the provided Releve object is valid before integration.
     *
     * @param releve The Releve object to be verified.
     * @return A ResultIntegration object indicating the verification result.
     */
    private ResultIntegration verfiyReleveBeforeIntegration(Releve releve) {

        if (validator.isNotValidIdReleve(releve.getIdReleve()))
            return new ResultIntegration("Identifiant du relevé erroné", "RELEVE001");
        if (validator.isNotValidNumCompteur(releve.getNumCompteur()))
            return new ResultIntegration("Numéro du compteur erroné", "RELEVE002");
        if (validator.isNotValidDateReleve(releve.getDateReleve()))
            return new ResultIntegration("Date de relevé erronée", "RELEVE003");
        if (validator.isNotValidNatureReleve(releve.getNatureReleve()))
            return new ResultIntegration("Nature de relevé erronée", "RELEVE004");
        if (validator.isNotValidOrigineReleve(releve.getOrigineReleve()))
            return new ResultIntegration("Origine de relevé erronée", "RELEVE005");
        if (validator.isNotValidIdPds(releve.getIdPds()))
            return new ResultIntegration("Identifiant PDS erroné", "RELEVE006");
        if (!checkPds(String.valueOf(releve.getIdPds())))
            return new ResultIntegration("Absence de PDS actif", "RELEVE021");
        if (validator.isNotValidDonneesMesures(releve.getDonneesMesures()))
            return new ResultIntegration("Objet donneeMesures vide", "RELEVE019");
        return isNotValidDonneesMesuresElements(releve);
    }


    /**
     * Verifies if the provided Releve.DonneesMesure object is valid before integration.
     *
     * @param releve The Releve object to be verified.
     * @return A ResultIntegration object indicating the verification result.
     */
    private ResultIntegration isNotValidDonneesMesuresElements(Releve releve) {
        List<DonneesMesure> donneesMesures = releve.getDonneesMesures();
        for (DonneesMesure donneesMesure : donneesMesures) {
            if (validator.isNotValidPosteHorosaisonnier(donneesMesure.getPosteHorosaisonnier()))
                return new ResultIntegration("Poste Horosaisonnier erroné", "RELEVE013");
            if (validator.isNotValidNatureMesure(donneesMesure.getNatureMesure()))
                return new ResultIntegration("Nature de la mesure erronée", "RELEVE014");
            if (validator.isNotValidMesure(donneesMesure.getMesure()))
                return new ResultIntegration("Mesure erronée", "RELEVE015");
            if (validator.isNotValidUnite(donneesMesure.getUnite()))
                return new ResultIntegration("Unite erronée", "RELEVE016");
        }
        if (validator.isNotValidDateReleveIndex(releves, releve))
            return new ResultIntegration("Index plus récent déjà existant", "RELEVE017");
        if (validator.isNotValidNatureReleveIndex(releves, releve))
            return new ResultIntegration("Aucun index précédent trouvé. Vérifier index de pose", "RELEVE018");
        return new ResultIntegration(true);
    }

    /**
     * Creates a result entry based on integration status and updates the source custom table "ct_releves_temp".
     *
     * @param id     The ID of the entry being processed.
     * @param result The integration result.
     * @param status The status of the integration.
     */
    private void makeResult(Object id, ResultIntegration result, Status status) {
        Map<String, Object> values = new HashMap<>();
        values.put(ID, id);
        if (status == Status.FAIL) {
            values.put(MESSAGE_ERREUR, result.getError());
            values.put(CODE_ERREUR, result.getCode());
        }
        values.put(STATUT, status.getValue());
        values.put(DATE_LAST_UPDATE, String.valueOf(new Date()));
        customTableService.update(CT_RELEVES_TEMP, values);
    }

    /**
     * Retrieves Releve information from a JSON content.
     *
     * @param contenu The JSON content containing Releve information.
     * @return A Releve object if parsing is successful, otherwise null.
     */
    private Releve getReleveInfo(String contenu) {
        try {
            return new ObjectMapper().readValue(contenu, Releve.class);
        } catch (Exception e) {
            return null;
        }
    }


    private boolean checkPds(String id_pds) {
        return pdsList.stream()
                .anyMatch(p -> p.get("id_pds").equals(id_pds));
    }

